import React from "react";

const CouponCard = () => {
  return (
    <div className="relative w-80 bg-white text-center rounded-xl shadow-lg border border-dashed border-gray-400 overflow-hidden">
      {/* 왼쪽 구멍 */}
      <div className="absolute top-1/2 -left-4 w-8 h-8 bg-gray-100 rounded-full z-10 -translate-y-1/2"></div>

      {/* 오른쪽 구멍 */}
      <div className="absolute top-1/2 -right-4 w-8 h-8 bg-gray-100 rounded-full z-10 -translate-y-1/2"></div>

      <div className="p-6">
        <h2 className="text-xl font-bold text-gray-800">🎟️ 할인 쿠폰</h2>
        <p className="text-gray-600 mt-2">20% 즉시 할인 적용</p>
        <button className="mt-4 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 transition">
          쿠폰 사용하기
        </button>
      </div>
    </div>
  );
};

export default CouponCard;
